  wire cpll_refclk;
  wire glblclk_i;
  wire glblclk_n;
  wire glblclk_p;
  wire glblclk_p_0;
  wire refclk_n;
  wire refclk_n_buffed;
  wire refclk_p;
  wire refclk_p_buffed;
  wire NLW_ibufds_refclk0_ODIV2_UNCONNECTED;

  (* BOX_TYPE = "PRIMITIVE" *) 
  BUFG glbl_bufg_i
       (.I(glblclk_i),
        .O(glblclk_p_0));
  (* BOX_TYPE = "PRIMITIVE" *) 
  (* CAPACITANCE = "DONT_CARE" *) 
  (* IBUF_DELAY_VALUE = "0" *) 
  (* IFD_DELAY_VALUE = "AUTO" *) 
  IBUFDS #(
    .IOSTANDARD("DEFAULT")) 
    i_glblclk_ibufds
       (.I(glblclk_p),
        .IB(glblclk_n),
        .O(glblclk_i));
  (* BOX_TYPE = "PRIMITIVE" *) 
  IBUFDS_GTE2 #(
    .CLKCM_CFG("TRUE"),
    .CLKRCV_TRST("TRUE"),
    .CLKSWING_CFG(2'b11)) 
    ibufds_refclk0
       (.CEB(1'b0),
        .I(refclk_p_buffed),
        .IB(refclk_n_buffed),
        .O(cpll_refclk),
        .ODIV2(NLW_ibufds_refclk0_ODIV2_UNCONNECTED));
  (* BOX_TYPE = "PRIMITIVE" *) 
  (* CAPACITANCE = "DONT_CARE" *) 
  (* IBUF_DELAY_VALUE = "0" *) 
  (* IFD_DELAY_VALUE = "AUTO" *) 
  IBUF #(
    .IOSTANDARD("DEFAULT")) 
    refclk_n_buf
       (.I(refclk_n),
        .O(refclk_n_buffed));
  (* BOX_TYPE = "PRIMITIVE" *) 
  (* CAPACITANCE = "DONT_CARE" *) 
  (* IBUF_DELAY_VALUE = "0" *) 
  (* IFD_DELAY_VALUE = "AUTO" *) 
  IBUF #(
    .IOSTANDARD("DEFAULT")) 
    refclk_p_buf
       (.I(refclk_p),
        .O(refclk_p_buffed));
